class RedisSessionStore:
    def __init__(self, host='localhost', port=6379, db=0, expire_seconds=3600):
        self.redis = redis.StrictRedis(host=host, port=port, db=db, decode_responses=True)
        self.expire_seconds = expire_seconds

    def get(self, session_id):
        data = self.redis.get(f'session:{session_id}')
        if data:
            self.redis.expire(f'session:{session_id}', self.expire_seconds)
            return json.loads(data)
        return {}

    def set(self, session_id, data):
        self.redis.setex(f'session:{session_id}', self.expire_seconds, json.dumps(data))

    def delete(self, session_id):
        self.redis.delete(f'session:{session_id}')

class RedisCache:
    def __init__(self, host='localhost', port=6379, db=1):
        self.redis = redis.StrictRedis(host=host, port=port, db=db, decode_responses=True)

    def get(self, key):
        return self.redis.get(key)

    def set(self, key, value, ex=60): # ex is expire time in seconds
        self.redis.setex(key, ex, value)

    def delete(self, key):
        self.redis.delete(key)

