class RedisSession:
    def __init__(self, app, session_store):
        self.app = app
        self.session_store = session_store
        self.app.before_request(self._load_session)
        self.app.after_request(self._save_session)

    def _load_session(self):
        session_id = request.cookies.get('session_id')
        if session_id:
            session.sid = session_id
            session.update(self.session_store.get(session_id))
        else:
            session.sid = str(uuid.uuid4())
            session.permanent = True # Set session to be permanent if you want it to last more than a browser session

    def _save_session(self, response):
        if session:
            self.session_store.set(session.sid, dict(session))
            response.set_cookie('session_id', session.sid, httponly=True)
        return response

RedisSession(app, redis_session_store)

def cached(ttl=60):
    def decorator(f):
        @functools.wraps(f)
        def wrapper(*args, **kwargs):
            # Create a cache key based on function name, args, and kwargs
            # For simplicity, we'll use a basic key. In a real app, you might serialize args/kwargs carefully.
            cache_key_parts = [f.__name__]
            cache_key_parts.extend(map(str, args))
            cache_key_parts.extend([f"{k}:{v}" for k, v in sorted(kwargs.items())])
            cache_key = ":".join(cache_key_parts)

            cached_result = redis_cache.get(cache_key)
            if cached_result:
                print(f"Cache hit for {cache_key}")
                return cached_result # Assume result is string, or deserialize if complex

            print(f"Cache miss for {cache_key}, computing...")
            result = f(*args, **kwargs)
            redis_cache.set(cache_key, str(result), ex=ttl) # Store as string
            return result
        return wrapper
    return decorator

